+// formatFrequencyForDisplay converts hours to display format
+func formatFrequencyForDisplay(hours int) string {
+	switch hours {
+	case 6:
+		return "6h"
+	case 12:
+		return "12h"
+	case 24:
+		return "24h"
+	case 48:
+		return "48h"
+	case 168:
+		return "weekly"
+	default:
+		return "24h"
+	}
+}
+
+// parseFrequencyFromDisplay converts display format to hours
+func parseFrequencyFromDisplay(display string) int {
+	switch display {
+	case "6h":
+		return 6
+	case "12h":
+		return 12
+	case "24h":
+		return 24
+	case "48h":
+		return 48
+	case "weekly":
+		return 168
+	default:
+		return 24
+	}
+}
+
